{
  "id": "mt-cli",
  "name": "Milestone Tracker CLI Sync",
  "version": "1.0.0",
  "description": "Integrates mt-cli into the GSD agent workflow — syncs task lifecycle events (claim, progress, block, complete) to the Milestone Tracker via mt-cli CLI calls",
  "tier": "project",
  "requires": { "platform": ">=2.29.0" },
  "provides": {
    "tools": [],
    "commands": ["mt-cli"],
    "hooks": [
      "execute-task",
      "complete-task"
    ]
  }
}

/**
 * Thin wrapper around the `mt-cli` CLI binary.
 *
 * Every public function returns `MtResult<T>` — never throws.
 * Uses `execFileSync` (not `execSync`) for safety.
 *
 * Architecture follows the github-sync/cli.js pattern.
 */
import { execFileSync } from "node:child_process";

// ─── Result Type ────────────────────────────────────────────────────────────

function ok(data) {
  return { ok: true, data };
}

function fail(error) {
  return { ok: false, error };
}

// ─── mt-cli Availability ────────────────────────────────────────────────────

let _mtCliAvailable = null;

/**
 * Check whether the `mt-cli` binary is available on PATH.
 * Result is cached for the lifetime of the process.
 */
export function mtCliIsAvailable() {
  if (_mtCliAvailable !== null) return _mtCliAvailable;
  try {
    execFileSync("mt-cli", ["--version"], {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"],
      timeout: 5_000,
    });
    _mtCliAvailable = true;
  } catch {
    _mtCliAvailable = false;
  }
  return _mtCliAvailable;
}

/** Reset cached availability (for testing). */
export function _resetMtCliCache() {
  _mtCliAvailable = null;
}

// ─── Helpers ────────────────────────────────────────────────────────────────

const MT_CLI_TIMEOUT = 30_000;

/**
 * Run an mt-cli command and return the raw stdout as a string.
 * Returns `MtResult<string>` — never throws.
 */
function runMtCli(args, cwd) {
  try {
    const stdout = execFileSync("mt-cli", args, {
      cwd,
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "pipe"],
      timeout: MT_CLI_TIMEOUT,
    }).trim();
    return ok(stdout);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return fail(msg);
  }
}

/**
 * Run an mt-cli command with `--json` and parse the output.
 * Returns `MtResult<object>` — never throws.
 */
function runMtCliJson(args, cwd) {
  const result = runMtCli([...args, "--json"], cwd);
  if (!result.ok) return fail(result.error);
  try {
    return ok(JSON.parse(result.data));
  } catch {
    return fail(`Failed to parse JSON from mt-cli: ${result.data.slice(0, 200)}`);
  }
}

// ─── Status / Bootstrap ─────────────────────────────────────────────────────

/**
 * Check mt-cli server connectivity and config.
 * Returns `MtResult<object>` with serverUrl, milestoneId, connected, etc.
 */
export function mtCliStatus(cwd) {
  return runMtCliJson(["status"], cwd);
}

/**
 * List tasks from the Milestone Tracker.
 * Returns `MtResult<object[]>` with task records.
 */
export function mtCliTasksList(cwd, opts = {}) {
  const args = ["tasks", "list"];
  if (opts.status) {
    args.push("--status", opts.status);
  }
  return runMtCliJson(args, cwd);
}

// ─── Task Lifecycle Commands ────────────────────────────────────────────────

/**
 * Claim a task for an agent.
 * @param {string} cwd - Working directory
 * @param {string} taskId - mt-cli task ID (short or full)
 * @param {object} opts - { agent?: string }
 * @returns {MtResult<object>} - Claimed task record
 */
export function mtCliTasksClaim(cwd, taskId, opts = {}) {
  const args = ["tasks", "claim", taskId];
  if (opts.agent) {
    args.push("--agent", opts.agent);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Update task progress.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { subTotal?, subDone?, message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksProgress(cwd, taskId, opts = {}) {
  const args = ["tasks", "progress", taskId];
  if (opts.subTotal !== undefined) {
    args.push("--sub-total", String(opts.subTotal));
  }
  if (opts.subDone !== undefined) {
    args.push("--sub-done", String(opts.subDone));
  }
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Block a task with a reason.
 * @param {string} cwd
 * @param {string} taskId
 * @param {string} reason - Required block reason
 * @returns {MtResult<object>}
 */
export function mtCliTasksBlock(cwd, taskId, reason) {
  const args = ["tasks", "block", taskId, "--reason", reason];
  return runMtCliJson(args, cwd);
}

/**
 * Unblock a task with an optional message.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksUnblock(cwd, taskId, opts = {}) {
  const args = ["tasks", "unblock", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  return runMtCliJson(args, cwd);
}

/**
 * Complete a task with optional evidence.
 * @param {string} cwd
 * @param {string} taskId
 * @param {object} opts - { message?, evidence?, filesTouched? }
 * @returns {MtResult<object>}
 */
export function mtCliTasksComplete(cwd, taskId, opts = {}) {
  const args = ["tasks", "complete", taskId];
  if (opts.message) {
    args.push("--message", opts.message);
  }
  if (opts.evidence) {
    args.push("--evidence", JSON.stringify(opts.evidence));
  }
  if (opts.filesTouched) {
    args.push("--files-touched", JSON.stringify(opts.filesTouched));
  }
  return runMtCliJson(args, cwd);
}

/**
 * Persistence layer for the mt-cli sync mapping.
 *
 * The mapping lives at `.gsd/mt-sync.json` and tracks which GSD
 * entities (milestones, slices, tasks) have been synced to the
 * Milestone Tracker via mt-cli, along with sync timestamps and status.
 *
 * Architecture follows the github-sync extension pattern.
 */
import { existsSync, readFileSync, writeFileSync, renameSync, mkdirSync, unlinkSync } from "node:fs";
import { join, dirname } from "node:path";
import { randomBytes } from "node:crypto";

const MAPPING_FILENAME = "mt-sync.json";

function mappingPath(basePath) {
  return join(basePath, ".gsd", MAPPING_FILENAME);
}

// ─── Local atomic write (avoids dependency on gsd/atomic-write.js) ─────────

/**
 * Simple atomic write: write to temp file then rename.
 * Safe for single-process use (which is all we need for this extension).
 */
function atomicWriteSync(filePath, content) {
  mkdirSync(dirname(filePath), { recursive: true });
  const tmpPath = filePath + `.tmp.${randomBytes(4).toString("hex")}`;
  writeFileSync(tmpPath, content, "utf-8");
  try {
    renameSync(tmpPath, filePath);
  } catch (err) {
    try { unlinkSync(tmpPath); } catch { /* best-effort cleanup */ }
    throw err;
  }
}

// ─── Load / Save ────────────────────────────────────────────────────────────

/**
 * Load the sync mapping from disk.
 * Returns null if the file doesn't exist, is corrupt, or has the wrong version.
 */
export function loadSyncMapping(basePath) {
  const path = mappingPath(basePath);
  if (!existsSync(path)) return null;
  try {
    const raw = readFileSync(path, "utf-8");
    const parsed = JSON.parse(raw);
    if (parsed?.version !== 1) return null;
    return parsed;
  } catch {
    return null;
  }
}

/**
 * Save the sync mapping to disk atomically.
 */
export function saveSyncMapping(basePath, mapping) {
  const path = mappingPath(basePath);
  atomicWriteSync(path, JSON.stringify(mapping, null, 2) + "\n");
}

/**
 * Create an empty sync mapping for a given milestone ID.
 */
export function createEmptyMapping(milestoneId) {
  return {
    version: 1,
    milestoneId,
    slices: {},
    tasks: {},
  };
}

// ─── Accessors ──────────────────────────────────────────────────────────────

/**
 * Get the record for a slice, or null if not synced.
 */
export function getSliceRecord(mapping, mid, sid) {
  return mapping.slices[`${mid}/${sid}`] ?? null;
}

/**
 * Get the record for a task, or null if not synced.
 */
export function getTaskRecord(mapping, mid, sid, tid) {
  return mapping.tasks[`${mid}/${sid}/${tid}`] ?? null;
}

/**
 * Get the mt-cli task ID for a GSD task, or null if not mapped.
 */
export function getMtTaskId(mapping, mid, sid, tid) {
  const record = getTaskRecord(mapping, mid, sid, tid);
  return record?.mtTaskId ?? null;
}

// ─── Mutators ───────────────────────────────────────────────────────────────

/**
 * Set (create or update) the record for a slice.
 */
export function setSliceRecord(mapping, mid, sid, record) {
  mapping.slices[`${mid}/${sid}`] = record;
}

/**
 * Set (create or update) the record for a task.
 */
export function setTaskRecord(mapping, mid, sid, tid, record) {
  mapping.tasks[`${mid}/${sid}/${tid}`] = record;
}

/**
 * Core GitHub sync engine.
 *
 * Entry point: `runGitHubSync()` — called from the GSD post-unit pipeline.
 * Routes to per-event sync functions based on the unit type, reads GSD
 * files to build GitHub entities, and persists the sync mapping.
 *
 * All errors are caught internally — sync failures never block execution.
 */
import { existsSync, readdirSync } from "node:fs";
import { join } from "node:path";
import { loadFile, parseSummary } from "../gsd/files.js";
import { parseRoadmap, parsePlan } from "../gsd/parsers-legacy.js";
import { resolveMilestoneFile, resolveSliceFile, resolveTaskFile, } from "../gsd/paths.js";
import { debugLog } from "../gsd/debug-logger.js";
import { loadEffectiveGSDPreferences } from "../gsd/preferences.js";
import { loadSyncMapping, saveSyncMapping, createEmptyMapping, getMilestoneRecord, getSliceRecord, getTaskRecord, setMilestoneRecord, setSliceRecord, setTaskRecord, } from "./mapping.js";
import { ghIsAvailable, ghHasRateLimit, ghDetectRepo, ghCreateIssue, ghCloseIssue, ghAddComment, ghCreateMilestone, ghCloseMilestone, ghCreatePR, ghMarkPRReady, ghMergePR, ghCreateBranch, ghPushBranch, ghAddToProject, } from "./cli.js";
import { formatMilestoneIssueBody, formatSlicePRBody, formatTaskIssueBody, formatSummaryComment, } from "./templates.js";
// ─── Entry Point ────────────────────────────────────────────────────────────
/**
 * Main sync entry point — called from GSD post-unit pipeline.
 * Routes to the appropriate sync function based on unit type.
 */
export async function runGitHubSync(basePath, unitType, unitId) {
    try {
        const config = loadGitHubSyncConfig(basePath);
        if (!config?.enabled)
            return;
        if (!ghIsAvailable()) {
            debugLog("github-sync", { skip: "gh CLI not available" });
            return;
        }
        // Resolve repo
        const repo = config.repo ?? resolveRepo(basePath);
        if (!repo) {
            debugLog("github-sync", { skip: "could not detect repo" });
            return;
        }
        // Rate limit check
        if (!ghHasRateLimit(basePath)) {
            debugLog("github-sync", { skip: "rate limit low" });
            return;
        }
        // Load or init mapping
        let mapping = loadSyncMapping(basePath) ?? createEmptyMapping(repo);
        mapping.repo = repo;
        // Parse unit ID parts
        const parts = unitId.split("/");
        const [mid, sid, tid] = parts;
        // Route by unit type
        switch (unitType) {
            case "plan-milestone":
                if (mid)
                    await syncMilestonePlan(basePath, mapping, config, mid);
                break;
            case "plan-slice":
            case "research-slice":
                if (mid && sid)
                    await syncSlicePlan(basePath, mapping, config, mid, sid);
                break;
            case "execute-task":
            case "reactive-execute":
                if (mid && sid && tid)
                    await syncTaskComplete(basePath, mapping, config, mid, sid, tid);
                break;
            case "complete-slice":
                if (mid && sid)
                    await syncSliceComplete(basePath, mapping, config, mid, sid);
                break;
            case "complete-milestone":
                if (mid)
                    await syncMilestoneComplete(basePath, mapping, config, mid);
                break;
        }
        saveSyncMapping(basePath, mapping);
    }
    catch (err) {
        debugLog("github-sync", { error: String(err) });
    }
}
export function shouldCreateSlicePrForSyncEvent(unitType, config) {
    return unitType === "complete-slice" && config.slice_prs !== false;
}
// ─── Per-Event Sync Functions ───────────────────────────────────────────────
async function syncMilestonePlan(basePath, mapping, config, mid) {
    // Skip if already synced
    if (getMilestoneRecord(mapping, mid))
        return;
    // Load roadmap data
    const roadmapPath = resolveMilestoneFile(basePath, mid, "ROADMAP");
    if (!roadmapPath)
        return;
    const content = await loadFile(roadmapPath);
    if (!content)
        return;
    const roadmap = parseRoadmap(content);
    const title = `${mid}: ${roadmap.title || "Milestone"}`;
    // Create GitHub Milestone
    const milestoneResult = ghCreateMilestone(basePath, mapping.repo, title, roadmap.vision || "");
    if (!milestoneResult.ok) {
        debugLog("github-sync", { phase: "create-milestone", error: milestoneResult.error });
        return;
    }
    const ghMilestoneNumber = milestoneResult.data;
    // Create tracking issue
    const issueBody = formatMilestoneIssueBody({
        id: mid,
        title: roadmap.title || "Milestone",
        vision: roadmap.vision,
        successCriteria: roadmap.successCriteria,
        slices: roadmap.slices?.map(s => ({
            id: s.id,
            title: s.title,
        })),
    });
    const issueResult = ghCreateIssue(basePath, {
        repo: mapping.repo,
        title: `${mid}: ${roadmap.title || "Milestone"} — Tracking`,
        body: issueBody,
        labels: config.labels,
        milestone: ghMilestoneNumber,
    });
    if (!issueResult.ok) {
        debugLog("github-sync", { phase: "create-tracking-issue", error: issueResult.error });
        return;
    }
    // Add to project if configured
    if (config.project) {
        ghAddToProject(basePath, mapping.repo, config.project, issueResult.data);
    }
    setMilestoneRecord(mapping, mid, {
        issueNumber: issueResult.data,
        ghMilestoneNumber,
        lastSyncedAt: new Date().toISOString(),
        state: "open",
    });
    debugLog("github-sync", {
        phase: "milestone-synced",
        mid,
        milestone: ghMilestoneNumber,
        issue: issueResult.data,
    });
}
async function syncSlicePlan(basePath, mapping, config, mid, sid) {
    const existingSlice = getSliceRecord(mapping, mid, sid);
    if (existingSlice)
        return;
    // Ensure milestone is synced first
    if (!getMilestoneRecord(mapping, mid)) {
        await syncMilestonePlan(basePath, mapping, config, mid);
    }
    const milestoneRecord = getMilestoneRecord(mapping, mid);
    // Load slice plan
    const planPath = resolveSliceFile(basePath, mid, sid, "PLAN");
    if (!planPath)
        return;
    const content = await loadFile(planPath);
    if (!content)
        return;
    const plan = parsePlan(content);
    const sliceBranch = `milestone/${mid}/${sid}`;
    // Create task sub-issues first (so we can link them in the PR body)
    const taskIssueNumbers = [];
    if (plan.tasks) {
        for (const task of plan.tasks) {
            // Skip if already synced
            if (getTaskRecord(mapping, mid, sid, task.id)) {
                const existing = getTaskRecord(mapping, mid, sid, task.id);
                taskIssueNumbers.push({ id: task.id, title: task.title, issueNumber: existing.issueNumber });
                continue;
            }
            const taskBody = formatTaskIssueBody({
                id: task.id,
                title: task.title,
                description: task.description,
                files: task.files,
                verifyCriteria: task.verify ? [task.verify] : undefined,
            });
            const taskResult = ghCreateIssue(basePath, {
                repo: mapping.repo,
                title: `${mid}/${sid}/${task.id}: ${task.title}`,
                body: taskBody,
                labels: config.labels,
                milestone: milestoneRecord?.ghMilestoneNumber,
                parentIssue: milestoneRecord?.issueNumber,
            });
            if (taskResult.ok) {
                setTaskRecord(mapping, mid, sid, task.id, {
                    issueNumber: taskResult.data,
                    lastSyncedAt: new Date().toISOString(),
                    state: "open",
                });
                taskIssueNumbers.push({ id: task.id, title: task.title, issueNumber: taskResult.data });
                if (config.project) {
                    ghAddToProject(basePath, mapping.repo, config.project, taskResult.data);
                }
            }
            else {
                taskIssueNumbers.push({ id: task.id, title: task.title });
            }
        }
    }
    setSliceRecord(mapping, mid, sid, {
        issueNumber: 0,
        prNumber: 0,
        branch: sliceBranch,
        lastSyncedAt: new Date().toISOString(),
        state: "open",
    });
    debugLog("github-sync", {
        phase: "slice-synced",
        mid,
        sid,
        pr: 0,
        taskIssues: taskIssueNumbers.filter(t => t.issueNumber).length,
    });
}
async function ensureSlicePullRequest(basePath, mapping, mid, sid) {
    const sliceRecord = getSliceRecord(mapping, mid, sid);
    if (!sliceRecord)
        return null;
    if (sliceRecord.prNumber)
        return sliceRecord.prNumber;
    const planPath = resolveSliceFile(basePath, mid, sid, "PLAN");
    if (!planPath)
        return null;
    const content = await loadFile(planPath);
    if (!content)
        return null;
    const plan = parsePlan(content);
    const sliceBranch = sliceRecord.branch || `milestone/${mid}/${sid}`;
    const milestoneBranch = `milestone/${mid}`;
    const branchResult = ghCreateBranch(basePath, sliceBranch, milestoneBranch);
    if (!branchResult.ok) {
        debugLog("github-sync", { phase: "create-slice-branch", error: branchResult.error });
    }
    const pushResult = ghPushBranch(basePath, sliceBranch);
    if (!pushResult.ok) {
        debugLog("github-sync", { phase: "push-slice-branch", error: pushResult.error });
        return null;
    }
    const tasks = (plan.tasks ?? []).map((task) => ({
        id: task.id,
        title: task.title,
        issueNumber: getTaskRecord(mapping, mid, sid, task.id)?.issueNumber,
    }));
    const prResult = ghCreatePR(basePath, {
        repo: mapping.repo,
        base: milestoneBranch,
        head: sliceBranch,
        title: `${sid}: ${plan.title || sid}`,
        body: formatSlicePRBody({
            id: sid,
            title: plan.title || sid,
            goal: plan.goal,
            mustHaves: plan.mustHaves,
            demoCriterion: plan.demo,
            tasks,
        }),
        draft: true,
    });
    if (!prResult.ok) {
        debugLog("github-sync", { phase: "create-slice-pr", error: prResult.error });
        return null;
    }
    sliceRecord.prNumber = prResult.data;
    sliceRecord.lastSyncedAt = new Date().toISOString();
    setSliceRecord(mapping, mid, sid, sliceRecord);
    return sliceRecord.prNumber;
}
async function syncTaskComplete(basePath, mapping, config, mid, sid, tid) {
    const taskRecord = getTaskRecord(mapping, mid, sid, tid);
    if (!taskRecord || taskRecord.state === "closed")
        return;
    // Load task summary
    let commentOk = true;
    const summaryPath = resolveTaskFile(basePath, mid, sid, tid, "SUMMARY");
    if (summaryPath) {
        const content = await loadFile(summaryPath);
        if (content) {
            const summary = parseSummary(content);
            const comment = formatSummaryComment({
                oneLiner: summary.oneLiner,
                body: summary.whatHappened,
                frontmatter: summary.frontmatter,
            });
            const commentResult = ghAddComment(basePath, mapping.repo, taskRecord.issueNumber, comment);
            commentOk = commentResult.ok;
            if (!commentResult.ok) {
                debugLog("github-sync", { phase: "task-comment-failed", mid, sid, tid, error: commentResult.error });
            }
        }
    }
    if (!commentOk)
        return;
    // Do not close the GitHub issue here. The task commit may still be local-only;
    // closing before the commit/PR reaches GitHub breaks the remote audit trail.
    // Commit trailers / PR merge should close linked issues once code is delivered.
    taskRecord.state = "open";
    taskRecord.lastSyncedAt = new Date().toISOString();
    setTaskRecord(mapping, mid, sid, tid, taskRecord);
    debugLog("github-sync", { phase: "task-complete-commented", mid, sid, tid, issue: taskRecord.issueNumber });
}
async function syncSliceComplete(basePath, mapping, config, mid, sid) {
    let sliceRecord = getSliceRecord(mapping, mid, sid);
    if (!sliceRecord) {
        await syncSlicePlan(basePath, mapping, config, mid, sid);
        sliceRecord = getSliceRecord(mapping, mid, sid);
    }
    if (!sliceRecord || sliceRecord.state === "closed")
        return;
    if (!sliceRecord.prNumber && shouldCreateSlicePrForSyncEvent("complete-slice", config)) {
        await ensureSlicePullRequest(basePath, mapping, mid, sid);
        sliceRecord = getSliceRecord(mapping, mid, sid);
        if (!sliceRecord || !sliceRecord.prNumber)
            return;
    }
    // Post slice summary as PR comment
    const summaryPath = resolveSliceFile(basePath, mid, sid, "SUMMARY");
    if (summaryPath && sliceRecord.prNumber) {
        const content = await loadFile(summaryPath);
        if (content) {
            const summary = parseSummary(content);
            const comment = formatSummaryComment({
                oneLiner: summary.oneLiner,
                body: summary.whatHappened,
                frontmatter: summary.frontmatter,
            });
            ghAddComment(basePath, mapping.repo, sliceRecord.prNumber, comment);
        }
    }
    // Mark PR ready for review, then merge
    if (sliceRecord.prNumber) {
        ghMarkPRReady(basePath, mapping.repo, sliceRecord.prNumber);
        // Squash-merge into milestone branch
        ghMergePR(basePath, mapping.repo, sliceRecord.prNumber, "squash");
    }
    sliceRecord.state = "closed";
    sliceRecord.lastSyncedAt = new Date().toISOString();
    setSliceRecord(mapping, mid, sid, sliceRecord);
    debugLog("github-sync", { phase: "slice-completed", mid, sid, pr: sliceRecord.prNumber });
}
async function syncMilestoneComplete(basePath, mapping, config, mid) {
    const record = getMilestoneRecord(mapping, mid);
    if (!record || record.state === "closed")
        return;
    // Close tracking issue
    ghCloseIssue(basePath, mapping.repo, record.issueNumber, `Milestone ${mid} completed.`);
    // Close GitHub milestone
    ghCloseMilestone(basePath, mapping.repo, record.ghMilestoneNumber);
    record.state = "closed";
    record.lastSyncedAt = new Date().toISOString();
    setMilestoneRecord(mapping, mid, record);
    debugLog("github-sync", { phase: "milestone-completed", mid });
}
// ─── Bootstrap ──────────────────────────────────────────────────────────────
/**
 * Walk the `.gsd/milestones/` tree and create GitHub entities for any
 * that are missing from the sync mapping. Safe to run multiple times.
 */
export async function bootstrapSync(basePath) {
    const config = loadGitHubSyncConfig(basePath);
    if (!config?.enabled)
        return { milestones: 0, slices: 0, tasks: 0 };
    if (!ghIsAvailable())
        return { milestones: 0, slices: 0, tasks: 0 };
    const repo = config.repo ?? resolveRepo(basePath);
    if (!repo)
        return { milestones: 0, slices: 0, tasks: 0 };
    let mapping = loadSyncMapping(basePath) ?? createEmptyMapping(repo);
    mapping.repo = repo;
    const taskCountBefore = Object.keys(mapping.tasks).length;
    const counts = { milestones: 0, slices: 0, tasks: 0 };
    const milestonesDir = join(basePath, ".gsd", "milestones");
    if (!existsSync(milestonesDir))
        return counts;
    const milestoneIds = readdirSync(milestonesDir, { withFileTypes: true })
        .filter(d => d.isDirectory())
        .map(d => d.name)
        .sort();
    for (const mid of milestoneIds) {
        if (!getMilestoneRecord(mapping, mid)) {
            await syncMilestonePlan(basePath, mapping, config, mid);
            counts.milestones++;
        }
        // Find slices
        const slicesDir = join(milestonesDir, mid, "slices");
        if (!existsSync(slicesDir))
            continue;
        const sliceIds = readdirSync(slicesDir, { withFileTypes: true })
            .filter(d => d.isDirectory())
            .map(d => d.name)
            .sort();
        for (const sid of sliceIds) {
            if (!getSliceRecord(mapping, mid, sid)) {
                await syncSlicePlan(basePath, mapping, config, mid, sid);
                counts.slices++;
            }
        }
    }
    counts.tasks = Object.keys(mapping.tasks).length - taskCountBefore;
    saveSyncMapping(basePath, mapping);
    return counts;
}
// ─── Config Loading ─────────────────────────────────────────────────────────
const _cachedConfigByBasePath = new Map();
function loadGitHubSyncConfig(basePath) {
    if (_cachedConfigByBasePath.has(basePath))
        return _cachedConfigByBasePath.get(basePath);
    try {
        const prefs = loadEffectiveGSDPreferences(basePath);
        const github = prefs?.preferences?.github;
        if (!github || typeof github !== "object") {
            _cachedConfigByBasePath.set(basePath, null);
            return null;
        }
        const config = github;
        _cachedConfigByBasePath.set(basePath, config);
        return config;
    }
    catch {
        _cachedConfigByBasePath.set(basePath, null);
        return null;
    }
}
/** Reset config cache (for testing). */
export function _resetConfigCache() {
    _cachedConfigByBasePath.clear();
}
function resolveRepo(basePath) {
    const result = ghDetectRepo(basePath);
    return result.ok ? result.data : null;
}
// ─── Commit Linking ─────────────────────────────────────────────────────────
/**
 * Look up the GitHub issue number for a task so the commit message
 * can include `Resolves #N`. Called from git-service commit building.
 */
export function getTaskIssueNumberForCommit(basePath, mid, sid, tid) {
    try {
        const config = loadGitHubSyncConfig(basePath);
        if (!config?.enabled)
            return null;
        if (config.auto_link_commits === false)
            return null;
        const mapping = loadSyncMapping(basePath);
        if (!mapping)
            return null;
        const record = getTaskRecord(mapping, mid, sid, tid);
        return record?.issueNumber ?? null;
    }
    catch {
        return null;
    }
}

/**
 * GitHub Sync extension for GSD.
 *
 * Opt-in extension that syncs GSD lifecycle events to GitHub:
 * milestones → GH Milestones + tracking issues, slices → draft PRs,
 * tasks → sub-issues with auto-close on commit.
 *
 * Integration happens via a single dynamic import in auto-post-unit.ts.
 * This index registers a `/github-sync` command for manual bootstrap
 * and status display.
 */
import { bootstrapSync } from "./sync.js";
import { loadSyncMapping } from "./mapping.js";
import { ghIsAvailable } from "./cli.js";
export default function (pi) {
    pi.registerCommand("github-sync", {
        description: "Bootstrap GitHub sync or show sync status",
        handler: async (args, ctx) => {
            const subcommand = args.trim().toLowerCase();
            if (subcommand === "status") {
                await showStatus(ctx);
                return;
            }
            if (subcommand === "bootstrap" || subcommand === "") {
                await runBootstrap(ctx);
                return;
            }
            ctx.ui.notify("Usage: /github-sync [bootstrap|status]", "info");
        },
    });
}
async function showStatus(ctx) {
    if (!ghIsAvailable()) {
        ctx.ui.notify("GitHub sync: `gh` CLI not installed or not authenticated.", "warning");
        return;
    }
    const mapping = loadSyncMapping(ctx.cwd);
    if (!mapping) {
        ctx.ui.notify("GitHub sync: No sync mapping found. Run `/github-sync bootstrap` to initialize.", "info");
        return;
    }
    const milestoneCount = Object.keys(mapping.milestones).length;
    const sliceCount = Object.keys(mapping.slices).length;
    const taskCount = Object.keys(mapping.tasks).length;
    const openMilestones = Object.values(mapping.milestones).filter(m => m.state === "open").length;
    const openSlices = Object.values(mapping.slices).filter(s => s.state === "open").length;
    const openTasks = Object.values(mapping.tasks).filter(t => t.state === "open").length;
    ctx.ui.notify([
        `GitHub sync: repo=${mapping.repo}`,
        `  Milestones: ${milestoneCount} (${openMilestones} open)`,
        `  Slices: ${sliceCount} (${openSlices} open)`,
        `  Tasks: ${taskCount} (${openTasks} open)`,
    ].join("\n"), "info");
}
async function runBootstrap(ctx) {
    if (!ghIsAvailable()) {
        ctx.ui.notify("GitHub sync: `gh` CLI not installed or not authenticated.", "warning");
        return;
    }
    ctx.ui.notify("GitHub sync: bootstrapping...", "info");
    try {
        const counts = await bootstrapSync(ctx.cwd);
        if (counts.milestones === 0 && counts.slices === 0 && counts.tasks === 0) {
            ctx.ui.notify("GitHub sync: everything already synced (or no milestones found).", "info");
        }
        else {
            ctx.ui.notify(`GitHub sync: created ${counts.milestones} milestone(s), ${counts.slices} slice(s), ${counts.tasks} task(s).`, "info");
        }
    }
    catch (err) {
        ctx.ui.notify(`GitHub sync bootstrap failed: ${err}`, "error");
    }
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerBlockCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('block <taskId>')
    .description('阻塞一个任务')
    .requiredOption('--reason <text>', '阻塞原因')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { reason: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/block`, {
          reason: opts.reason,
        });

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已阻塞 #${result.shortId}「${result.title}」`);
        console.log(`  原因: ${result.blockedReason}`);
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { progressBar } from '../utils/format.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerProgressCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('progress <taskId>')
    .description('更新任务进度')
    .option('--sub-total <n>', '子任务总数', parseInt)
    .option('--sub-done <n>', '已完成子任务数', parseInt)
    .option('--message <msg>', '进度说明')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { subTotal?: number; subDone?: number; message?: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const body: Record<string, unknown> = {};
        if (opts.message) body.progressMessage = opts.message;
        if (opts.subTotal !== undefined) body.subTotal = opts.subTotal;
        if (opts.subDone !== undefined) body.subDone = opts.subDone;

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/progress`, body);

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已更新 #${result.shortId}「${result.title}」的进度`);
        if (result.subTotal > 0) {
          console.log(`  ${progressBar(result.subDone, result.subTotal)} (${result.subDone}/${result.subTotal})`);
        }
        if (result.progressMessage) {
          console.log(`  说明: ${result.progressMessage}`);
        }
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

