    assertEqual(typeof sync.getSyncStatus, "function", "getSyncStatus is exported as function");
    assertEqual(typeof sync.setDebugLog, "function", "setDebugLog is exported as function");
    console.log("  ✓ exports correct types");
  }

  // ── Test 2: setDebugLog accepts a function ──
  {
    const sync = await import("../../sync.js");
    let logged = null;
    sync.setDebugLog((ch, data) => { logged = { ch, data }; });
    assert(logged === null, "setDebugLog does not call immediately");

    // Trigger a debug log via bootstrapSync (which will skip due to no mt-cli)
    await sync.bootstrapSync(basePath);
    // Should have logged something since mt-cli is likely not available
    assert(logged !== null, "debugLog was called during bootstrapSync");
    console.log("  ✓ setDebugLog wires correctly");
  }

  // ── Test 3: bootstrapSync returns zeros when mt-cli unavailable ──
  {
    const sync = await import("../../sync.js");
    const result = await sync.bootstrapSync(basePath);
    assertEqual(typeof result, "object", "bootstrapSync returns an object");
    assertEqual(typeof result.milestones, "number", "bootstrapSync returns milestones count");
    assertEqual(typeof result.slices, "number", "bootstrapSync returns slices count");
    assertEqual(typeof result.tasks, "number", "bootstrapSync returns tasks count");
    console.log("  ✓ bootstrapSync returns correct shape");
  }

  // ── Test 4: getSyncStatus returns null when no mapping ──
  {
    const sync = await import("../../sync.js");
    const fs = await import("node:fs");
    const path = await import("node:path");
    const os = await import("node:os");

