    assertEqual(status.slicesCompleted, 1, "slicesCompleted correct");
    assertEqual(status.tasksTotal, 3, "tasksTotal correct");
    assertEqual(status.tasksMapped, 2, "tasksMapped correct");
    assertEqual(status.tasksUnmapped, 1, "tasksUnmapped correct");
    assertEqual(status.tasksCompleted, 1, "tasksCompleted correct");

